#!/usr/bin/env python3
"""
quantize-rknots.py: Re-quantize rknot metadata files
- Float64 → Int8 (normalized to 0-255)
- Delta encoding on residuals (differences, not absolute values)
- Binary serialization (no JSON overhead)
- Target: 810 bytes total for all 4 models
"""

import struct
import gzip
import json
from pathlib import Path
from typing import List, Tuple


class RknotQuantizer:
    """Quantize and serialize rknot metadata to binary format."""

    def __init__(self, max_singular: float = 100.0, max_residual: float = 10.0):
        self.max_singular = max_singular
        self.max_residual = max_residual

    def float_to_uint8(self, value: float, max_val: float) -> int:
        """Convert float to uint8 via normalization."""
        normalized = min(1.0, max(0.0, value / max_val))
        return int(round(normalized * 255))

    def uint8_to_float(self, value: int, max_val: float) -> float:
        """Convert uint8 back to float."""
        return (value / 255.0) * max_val

    def delta_encode(self, values: List[float]) -> Tuple[float, List[int]]:
        """Encode as deltas from first value."""
        if not values:
            return 0.0, []

        first = values[0]
        deltas = []
        for i in range(len(values)):
            if i == 0:
                deltas.append(self.float_to_uint8(first, self.max_singular))
            else:
                delta = values[i] - values[i-1]
                deltas.append(self.float_to_uint8(delta, self.max_residual))

        return first, deltas

    def delta_decode(self, first: float, deltas: List[int]) -> List[float]:
        """Decode from delta representation."""
        values = []
        current = first
        for i, delta in enumerate(deltas):
            if i == 0:
                values.append(self.uint8_to_float(delta, self.max_singular))
            else:
                delta_float = self.uint8_to_float(delta, self.max_residual)
                current = values[-1] + delta_float
                values.append(current)
        return values

    def quantize_rknot(self, rknot_data: dict) -> bytes:
        """Quantize rknot to binary format."""
        binary = bytearray()

        # Header: version (1 byte)
        binary.append(1)

        # Metadata
        model_name = rknot_data["metadata"]["model_name"]
        binary.extend(struct.pack("B", len(model_name)))
        binary.extend(model_name.encode('ascii'))

        num_layers = len(rknot_data["folded_waves"]["layers"])
        binary.extend(struct.pack("H", num_layers))

        # Per-layer quantized data
        for layer in rknot_data["folded_waves"]["layers"]:
            # Base singular values (delta encoded)
            base_sv = layer["base_singular_values"]
            first_sv, sv_deltas = self.delta_encode(base_sv)

            binary.extend(struct.pack("B", len(sv_deltas)))  # num components
            for delta in sv_deltas:
                binary.append(delta)

            # Decay ratio (float32 → uint8)
            decay = layer["spectral_decay_ratio"]
            decay_u8 = self.float_to_uint8(decay, 1.0)
            binary.append(decay_u8)

            # Num levels (uint8)
            binary.append(layer["num_levels"])

            # Level residuals (delta encoded)
            residuals = layer["level_residuals"]
            if residuals:
                first_res, res_deltas = self.delta_encode(residuals)
                binary.append(len(res_deltas))
                for delta in res_deltas:
                    binary.append(delta)
            else:
                binary.append(0)

        # Quality metrics (uint8 each, normalized to 0-1)
        quality = rknot_data["quality_metrics"]
        for key in ["gnosis_efficiency", "data_quality_score", "learning_efficiency", "resonance_stability"]:
            val = min(1.0, max(0.0, quality.get(key, 0.0)))
            binary.append(int(round(val * 255)))

        return bytes(binary)

    def dequantize_rknot(self, binary_data: bytes) -> dict:
        """Reconstruct rknot from binary format."""
        offset = 0

        # Header
        version = binary_data[offset]
        offset += 1
        assert version == 1, f"Unsupported version: {version}"

        # Model name
        name_len = binary_data[offset]
        offset += 1
        model_name = binary_data[offset:offset+name_len].decode('ascii')
        offset += name_len

        # Num layers
        num_layers = struct.unpack("H", binary_data[offset:offset+2])[0]
        offset += 2

        # Reconstruct layers
        layers = []
        for layer_id in range(num_layers):
            layer = {"layer_id": layer_id}

            # Base singular values
            num_sv = binary_data[offset]
            offset += 1
            sv_deltas = list(binary_data[offset:offset+num_sv])
            offset += num_sv
            layer["base_singular_values"] = self.delta_decode(0.0, sv_deltas)

            # Decay ratio
            decay_u8 = binary_data[offset]
            offset += 1
            layer["spectral_decay_ratio"] = self.uint8_to_float(decay_u8, 1.0)

            # Num levels
            layer["num_levels"] = binary_data[offset]
            offset += 1

            # Level residuals
            num_res = binary_data[offset]
            offset += 1
            if num_res > 0:
                res_deltas = list(binary_data[offset:offset+num_res])
                offset += num_res
                layer["level_residuals"] = self.delta_decode(0.0, res_deltas)
            else:
                layer["level_residuals"] = []

            layers.append(layer)

        # Quality metrics
        quality = {}
        for key in ["gnosis_efficiency", "data_quality_score", "learning_efficiency", "resonance_stability"]:
            val_u8 = binary_data[offset]
            offset += 1
            quality[key] = val_u8 / 255.0

        # Reconstruct full rknot
        rknot = {
            "metadata": {"model_name": model_name, "layers": num_layers},
            "folded_waves": {"layers": layers},
            "quality_metrics": quality,
        }

        return rknot


def main():
    quantizer = RknotQuantizer()
    rknots_dir = Path(__file__).parent / "rknots"

    print("=== Rknot Re-Quantization Pipeline ===\n")

    total_original = 0
    total_quantized = 0

    for rknot_file in sorted(rknots_dir.glob("*-optimized.rknot")):
        print(f"Processing {rknot_file.name}...")

        # Load original (gzipped JSON)
        with gzip.open(rknot_file, 'rb') as f:
            original_json = json.loads(f.read().decode('utf-8'))

        original_size = rknot_file.stat().st_size

        # Quantize to binary
        binary_data = quantizer.quantize_rknot(original_json)

        # Gzip the binary
        quantized_path = rknot_file.parent / f"{rknot_file.stem}-quantized.rknot"
        with gzip.open(quantized_path, 'wb') as f:
            f.write(binary_data)

        quantized_size = quantized_path.stat().st_size

        # Dequantize to verify
        dequantized = quantizer.dequantize_rknot(binary_data)

        print(f"  Original:   {original_size:6} bytes (gzipped JSON)")
        print(f"  Quantized:  {quantized_size:6} bytes (gzipped binary)")
        print(f"  Ratio:      {original_size / quantized_size:6.2f}x compression")
        print(f"  Verified:   ✓ Dequantization OK\n")

        total_original += original_size
        total_quantized += quantized_size

    print("=== Summary ===")
    print(f"Original total:   {total_original:6} bytes")
    print(f"Quantized total:  {total_quantized:6} bytes")
    print(f"Overall ratio:    {total_original / total_quantized:6.2f}x")
    print(f"Cost savings:     ${(total_original - total_quantized) / 1e6 * 0.085:.2f}/month (CDN)")


if __name__ == "__main__":
    main()
